def solve():
    n = int(input())
    s = input().strip()
    count = {'B': 0, 'G': 0, 'R': 0}
    for c in s:
        count[c] += 1

    res = set()

    # Check if all three colors are present
    if count['B'] > 0 and count['G'] > 0 and count['R'] > 0:
        res.update(['B', 'G', 'R'])
    else:
        # Check for two colors
        colors = []
        for c in count:
            if count[c] > 0:
                colors.append(c)
        if len(colors) == 2:
            c1, c2 = colors
            if count[c1] == 1 and count[c2] == 1:
                res.add({'B', 'G', 'R'}.difference({c1, c2}).pop())
            else:
                res.add(c1)
                res.add(c2)
        else:
            # Only one color
            res.add(colors[0])

    # Check for parity conditions
    if len(res) > 1:
        # If any two counts have the same parity, the third color is possible
        if (count['B'] % 2) == (count['G'] % 2):
            res.add('R')
        if (count['B'] % 2) == (count['R'] % 2):
            res.add('G')
        if (count['G'] % 2) == (count['R'] % 2):
            res.add('B')

    print(''.join(sorted(res)))

